#include <bits/stdc++.h> // Include standard libraries for input/output and other utilities

using namespace std;

// Array to hold the elements for each test case
int d[55];

int main() {
    // Optimize input/output
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int T; // Variable to hold the number of test cases
    cin >> T; // Read the number of test cases
    assert(T >= 1 && T <= 10000); // Ensure T is within valid limits

    // Loop over each test case
    while (T--) {
        int n; // Variable to hold the number of elements in the current test case
        cin >> n; // Read the number of elements
        assert(n >= 1 && n <= 50); // Ensure n is within valid limits

        // Use a set to count distinct elements in array d
        set<int> st; // Set to hold distinct elements
        for (int i = 0; i < n; i++) {
            cin >> d[i]; // Read each element into the array
            assert(d[i] >= 1 && d[i] <= 100); // Ensure each element is within valid limits
            st.insert(d[i]); // Insert the element into the set (duplicates are ignored)
        }

        // Output the number of distinct elements
        cout << st.size() << endl;
    }

    return 0; // Return 0 to indicate successful completion
}

