#include <stdio.h>
#include <stdlib.h>

#define MAX 55  // Maximum size of the array

int d[MAX];  // Array to hold input values

// Comparison function for qsort
int compare(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);  // Compare two integers
}

int main() {
    int T;  // Number of test cases
    scanf("%d", &T);  // Read the number of test cases

    // Assert equivalent: Check if T is within valid range
    if (T < 1 || T > 10000) {
        return 1; // Exit if T is out of bounds
    }

    // Process each test case
    while (T--) {
        int n;  // Number of elements in the current test case
        scanf("%d", &n);  // Read the number of elements

        // Assert equivalent: Check if n is within valid range
        if (n < 1 || n > 50) {
            return 1; // Exit if n is out of bounds
        }

        // Variable to count distinct elements
        int distinct_count = 0;

        // Read the elements into the array
        for (int i = 0; i < n; i++) {
            scanf("%d", &d[i]);  // Read each element
            // Assert equivalent: Check if the element is within valid range
            if (d[i] < 1 || d[i] > 100) {
                return 1; // Exit if the element is out of bounds
            }
        }

        // Sort the array to facilitate counting distinct elements
        qsort(d, n, sizeof(int), compare);

        // Count distinct elements in the sorted array
        for (int i = 0; i < n; i++) {
            // If it’s the first element or different from the previous one, increment count
            if (i == 0 || d[i] != d[i - 1]) {
                distinct_count++;  // Increment the distinct count
            }
        }

        // Output the number of distinct elements
        printf("%d\n", distinct_count);
    }

    return 0;  // Exit the program successfully
}

