import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main(String[] args) throws java.lang.Exception {
        // Input handling
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();  // Read number of test cases
        assert T >= 1 && T <= 10000;  // Constraint check

        while (T-- > 0) {
            int n = sc.nextInt();  // Read size of the array
            assert n >= 1 && n <= 50;  // Constraint check

            // Use a HashSet to count distinct elements
            Set<Integer> st = new HashSet<>();
            for (int i = 0; i < n; i++) {
                int value = sc.nextInt();  // Read array element
                assert value >= 1 && value <= 100;  // Constraint check
                st.add(value);  // Add element to the set
            }

            // Output the count of distinct elements
            System.out.println(st.size());
        }

        sc.close();  // Close the scanner
    }
}

