const readline = require('readline');

// Create an interface for reading input
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

// Variable to store input
let input = [];

// Read input line by line
rl.on('line', (line) => {
    input.push(line);
});

// Process the input when the stream is closed
rl.on('close', () => {
    let T = parseInt(input[0]); // Number of test cases
    let index = 1;

    // Process each test case
    while (T-- > 0) {
        let n = parseInt(input[index]); // Size of the array
        let A = input[index + 1].split(' ').map(Number); // Array elements

        // Sort the array to make duplicate checking easier
        A.sort((a, b) => a - b);

        // Variable `c` to count the number of unique elements
        let c = n; // Initially assume all elements are unique

        // Check for duplicates
        for (let i = 1; i < n; i++) {
            if (A[i] === A[i - 1]) {
                c--; // Decrease count if a duplicate is found
            }
        }

        // Output the number of unique elements
        console.log(c);
        index += 2; // Move to the next test case in input
    }
});
